var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그러니까…….","JPN":"つまり……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"여긴 침식체 뱃속이라는 거죠?","JPN":"ここは侵食体のお腹の中ってことですよね？","ENG":"We're inside the C.O.'s belly?","TWN":"我們在侵蝕體的肚子裡，對吧？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"아하하. 정확하시네요. 소화되지 않은 것만 해도 다행이죠?","JPN":"あはは、その通りです。消化されていないだけでも幸運ですよ。","ENG":"Ah hah hah. That's correct. Aren't you glad you weren't digested?","TWN":"呵呵呵，猜對囉。沒被消化掉算是不幸中的大幸吧？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"다행…… ","JPN":"幸運…… ","ENG":"Glad...?","TWN":"不幸中的……大幸？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"은 아니죠!","JPN":"そんなわけないでしょ！","ENG":"As if!","TWN":"才不是！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그럼 천천히 죽기랑 빨리 죽기 중에 선택하라는 것 아니에요?","JPN":"結局ゆっくり死んでいくか、すぐに死んでしまうかのどちらかを選ぶしかないじゃないですか。","ENG":"Then, we're forced to choose between a quick or a slow death!","TWN":"那不就是要在快點死和慢點死裡面選一個嗎！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"보기보단 똑똑한 분이시군요.","JPN":"案外鋭いですね。","ENG":"You're smarter than you look.","TWN":"沒想到你蠻聰明的嘛。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그렇게 빨리 인정하지 마세요! 그럼 당신은 뭔데 여기 있는 건데요?","JPN":"そんなにあっさりと認めないでください！　じゃあ、あなたは誰で、どうしてここにいるんですか？","ENG":"Don't be so quick to admit it! Then what are you doing here?","TWN":"不要那麼快承認！那你又是什麼人，為什麼在這裡？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"역시 그림자인 거지!","JPN":"やっぱりシャドウなんだ！","ENG":"I knew it! You are a Shadow!","TWN":"果然是暗影吧！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"그럼 여기, 제 워치를 보여드릴게요.","JPN":"じゃあこれ、私のウォッチを見てください。","ENG":"Here, I'll show you my Watch, then.","TWN":"你看，這是我的能量環。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"자, 여기 아직 초침이 움직이는 게 보이시나요?","JPN":"はい、まだ針が動いているのが見えますか？","ENG":"Look. See how that second hand is still moving?","TWN":"你還能看到秒針在動吧？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"……일단 그림자가 아닐 수도 있다는 가능성을 염두에 둘게요.","JPN":"……まぁ、とりあえず、シャドウじゃない可能性は念頭に置いておきます。","ENG":"...I'll keep note that you might not be a Shadow, then.","TWN":"……我會考慮你不是暗影的可能性。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"아하하. 냉정하셔라. 그럼 이제 여길 빠져나가지 못한 이유도 설명해 드려야겠죠?","JPN":"あはは、冷静ですね。では、私がどうしてここから脱出できていないのかもお話しますね。","ENG":"Ah hah hah. How calm. Now, I should explain why I haven't been able to get out of here as well.","TWN":"呵呵呵，真是冷靜。那麼我還得解釋下為什麼沒能離開這裡的原因吧？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"여기, 지팡이 위로 뜬 홀로그램에서 계속 좌표가 변하는 게 보이세요?","JPN":"この、杖が出しているホログラムの座標が変化し続けているのがわかりますか？","ENG":"Here. Do you see how the coordinates that appear on the hologram above the staff keep changing?","TWN":"這裡，我這杖上的全息圖，裡面的座標在不斷地變化，你有看到吧？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"이 침식체는 허수 공간과 현실 세계를 헤엄치는 특징이 있어요.","JPN":"この侵食体は、虚数空間と現実世界の狭間を泳ぐかのように、行き来することが特徴です。","ENG":"This C.O.'s nature is swimming in both the imaginary space and the Normalside.","TWN":"這個侵蝕體的特色，就是會在虛數空間和現實世界之間遊走。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"허수 공간은 시시각각 좌표가 왜곡되는데, 그건 이 침식체의 내부에도 영향을 끼치죠.","JPN":"虚数空間は座標が常に歪み続けており、それはこの侵食体の身体の内部にも影響を及ぼします。","ENG":"The imaginary space continuously distorts the coordinates, which also affects the inside of the C.O.","TWN":"虛數空間中的座標時刻在扭曲，也會影響到侵蝕體的內部。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"계속해서 같은 곳으로 나온다든가, 출구가 어느 날 막혀 있다든가 하는 일들이 일어나요.","JPN":"ずっと同じところをぐるぐる回ったり、出口が塞がっていたリ、そのようなことの繰り返しです。","ENG":"Odd things happen, like returning to the same place over again, or having the exit blocked one day.","TWN":"常常會發生奇怪的事，比如總是從同一個地方出來，或者某天出口被堵住之類的。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"흠…… 진실인지 아닌지는 확인해 봐야 알겠어요.","JPN":"うーん……それが本当かどうかは、自分で見るまではなんとも言えませんね。","ENG":"Hmm... I need to see if what you say is true or not.","TWN":"嗯……是真是假，還得確認一下才知道。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"이런 곳일수록 의심이 많은 게 좋죠. 그래야 살 확률이 올라가는 법이니까요.","JPN":"疑うことは、こういう場所では大切です。生存率を高めてくれますからね。","ENG":"It's better to be skeptical when you're in a place like this. It only increases your odds of survival.","TWN":"在這種地方多疑是好事，這樣才能提高生存幾率。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"어쩌다가 여기 오게 되신 거예요? 현실에 오래 머무르는 침식체가 아닌데.","JPN":"どうしてここに来ることになったのですか？　現実世界に長く出現するような侵食体ではないのですが。","ENG":"How did you get here? This C.O. doesn't really stay on the Normalside for that long.","TWN":"不過你是怎麼來到這裡的？這個侵蝕體是不會長時間停留在現世中的。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"습격을 당했어요.","JPN":"奇襲を受けてしまったんです。","ENG":"We were attacked.","TWN":"我們遭到它的攻擊。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저와 함께하던 카운터께서 어떻게든 이 침식체를 막아내려고 했지만…….","JPN":"私と一緒にいたカウンター様が、こいつと戦ってくれましたが……","ENG":"The Counter I was with tried to stop it, but...","TWN":"和我一起的制裁者想盡辦法要阻止它，但是……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"제가 다치는 바람에 제대로 싸우지 못하셨죠.","JPN":"私が怪我をしたせいで、思うように戦うことができなくなってしまって。","ENG":"I got wounded and she couldn't fight properly because of that.","TWN":"後來因為我受傷，害她無法繼續戰鬥。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그리고 나서 제가 먹혔으니, 어쩌면 그분도 여기 계실 수도 있겠어요.","JPN":"そのあと私は食べられてしまったので、もしかしたらその方もここにいらっしゃるかもしれません。","ENG":"And since I've been swallowed by it, maybe she's also somewhere around here.","TWN":"然後我就被這個侵蝕體吞掉了，或許她也在這裡面。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"제가 원하는 결말은 아니지만…….","JPN":"そうではないことを願ってはいますが……","ENG":"This isn't really the ending I was hoping for, but...","TWN":"這不是我想要的結局……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"이 침식체가 현실 세계를 자주 넘나드는 녀석은 아닌데…… 운이 나빴군요.","JPN":"この侵食体は現実世界に頻繁に現れるような個体ではないのですが……運が悪かったですね。","ENG":"This C.O. isn't really one that crosses into the Normalside... I guess you were unlucky.","TWN":"這個侵蝕體並不常躍入現世……你的運氣真差。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이렇게 된 거, 저는 여기서 살아나가고 싶어요.","JPN":"こうなったら、ここから生きて出たくなりました。","ENG":"With everything that has happened, I want to get out of here alive.","TWN":"即使這樣，我還是想從這裡活著出去。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그 사람한테 못다 한 말이 있거든요. 꼭 그 사람을 보고 얘기해야 해요.","JPN":"あの方に言いそびれたことがあるんです。必ず直接会って言ってあげなくちゃ。","ENG":"There are things that I couldn't tell her, and I want to tell her in person.","TWN":"我還有話沒對那個人說完，一定要見到她親口說。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"많이 소중한 사람이었나 보네요.","JPN":"すごく大切な方だったんですね。","ENG":"You seem to care a lot about her.","TWN":"看來那個人對你來說很重要。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"자신의 안위보다 그분과 만나는 걸 먼저 생각하시다니.","JPN":"自分のことより、その方に会いたい気持ちが勝ってしまうなんて。","ENG":"Prioritizing meeting this person above your own safety.","TWN":"竟然把自己的性命看得比跟她見面還重要。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"만난 시간은 짧았지만, 서로 공통점이 많았어요.","JPN":"出会って間もないのですが、お互い似ているところが多かったんです。","ENG":"Our time together was short, but we had a lot in common.","TWN":"雖然相處的時間很短，但我們有很多共同點。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"둘 다 중요한 걸 잃어버렸고, 함께 협력도 하고…… 생각보다 정이 많이 든 모양이에요.","JPN":"あの方も私も、大事なものを失くしていて、それで力を貸しあって……そうしていると、いつの間にか情がわいちゃって……","ENG":"We both lost something important to us, and while we helped each other out... I think I got attached to her more than I thought I did.","TWN":"我們都失去了重要的東西，還一起合作……感情似乎在這過程中加深了。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"물론, 그 결말이 이렇게 될 줄은 몰랐지만…… 죄책감에 시달리고 있을까 봐 걱정이네요.","JPN":"ただ、まさかこんな結末を迎えるとは思いませんでした……あの方が自分を責めていそうで、心配です。","ENG":"Of course, I didn't know we'd end up like this... I'm just worried that she might be guilt-ridden.","TWN":"當然，沒想到最後會變成這樣……我擔心她會因此責備自己。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"무슨 마음인지 알 것 같아요.","JPN":"お気持ちがわかる気がします。","ENG":"I think I know what you mean.","TWN":"我好像明白你的心情了。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"저도 그렇게 짐을 떠넘기고 여기 오게 됐거든요.","JPN":"私も同じく責任を押しつけて、ここに来ましたから。","ENG":"I also had to leave some things behind before coming here.","TWN":"我也是這樣把擔子卸下來，來到這裡的。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"오, 그러고 보니 이걸로 저희도 공통점이 생긴 건가요?","JPN":"おっ、ということは、私たちにも共通点が出来ましたね。","ENG":"Oh, come to think of it, do we have something in common as well?","TWN":"嗯嗯，這麼說來，我們也有些共同點嘛？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"꽤 오랜 시간 혼자 지냈더니, 이런 얘기도 굉장히 즐겁네요.","JPN":"すごく長い間一人だったから、こんな話すらも楽しく感じます。","ENG":"I've been alone here for such a long time, just talking to you is so much fun.","TWN":"我獨自生活了很長時間，能和你聊這些話題真是愉快。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"예전에 도시 째로 이곳에 휘말린 사람들도 있었는데, 그분들은 얼마 못 가서 전부 침식체가 되어버렸거든요.","JPN":"過去に都市が飲み込まれたときに、入ってきた人たちがいましたが、しばらくして皆侵食体になってしまったんです。","ENG":"I heard there was a city that got swallowed whole a while back, but they all turned into C.O.s not long after.","TWN":"以前也有整個城市的人被捲入這裡，但他們過沒多久就全都變成了侵蝕體。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"……에리두로군요.","JPN":"……エリドゥのことですね。","ENG":"...You're talking about Eridu.","TWN":"……是埃里都吧。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"오래전부터 그 도시를 만나길 학수고대했는데…… 이렇게 마주할 줄은 몰랐네요.","JPN":"昔からあの都市に行くことを夢見ていたのに……まさかこんな形で叶うことになるなんて。","ENG":"I was hoping that I'd get to see that city one day... but didn't imagine it would be like this.","TWN":"我一直期待著能見到那座城市……沒想到會以這樣的方式相遇。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"하지만…… 그 일은 20년 전의 이야기예요.","JPN":"でも……その事件はもう20年も前のことです。","ENG":"But... that was twenty years ago.","TWN":"但是……那是20年前的事了。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그렇다는 건…… 당신도 역시 그때의 사람이란 말씀이군요.","JPN":"ということは……やっぱりあなたも当時の人間なんですね。","ENG":"Then that means... you're also someone from around that time.","TWN":"也就是說……你果然也是那時候的人吧？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"아하하…… 시간이 벌써 그렇게 흘렀나요?","JPN":"あはは……もうそんなに時間が経っちゃったんですね。","ENG":"Ah hah hah... Has it been that long already?","TWN":"呵呵呵……都已經過這麼久了嗎？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"예상은 하고 있었지만…… 여기선 시간의 흐름을 잘 알 수 없어서요.","JPN":"そうだろうとは思っていましたが……ここにいると時間の流れがよくわからなくなるんです。","ENG":"I suspected as much, but... it's hard to tell the time here.","TWN":"雖然有料到……但在這裡很難察覺時間的流逝。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"일단, 여기서 살아나갈 방법을 찾아야겠어요.","JPN":"とにかく、ここから無事に出ていく方法を見つけないとですね。","ENG":"First, let's try to find a way to get out of here alive.","TWN":"首先，我們得想辦法在這裡活下去。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"주저앉아서 한숨만 푹푹 쉬는 것보다는…….","JPN":"何もせずに嘆いているぐらいなら……","ENG":"Instead of giving up and doing nothing...","TWN":"與其坐在那裡歎氣……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"조금이라도 나아가는 게 맞다고 생각하거든요.","JPN":"少しでもできることをやらなきゃって思うんです。","ENG":"I think we should try to make some kind of progression.","TWN":"哪怕有一點進展都是好的。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"본받아야 할 자세예요.","JPN":"私も見習うべきですね。","ENG":"I should adopt your attitude.","TWN":"這是值得學習的態度。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"WIND_VARUNA_NULL_GIRL","text":{"KOREA":"그럼 움직이실까요?","JPN":"ではそうしましょう。","ENG":"Shall we get going?","TWN":"那麼，我們開始行動吧？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"WIND_VARUNA_NULL_GIRL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그러니까…… 당신 이름이 뭐죠?","JPN":"えっと……なんて呼べばいいですか？","ENG":"Um... Do you have a name?","TWN":"那個……你叫什麼名字？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"통성명도 안 하고 있었네요.","JPN":"まだお互い、名前も名乗っていませんでしたね。","ENG":"I don't think we ever introduced ourselves.","TWN":"我們還沒彼此自我介紹呢。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그냥 <color=#ffd34c>바람</color>이라고 불러주세요.","JPN":"<color=#ffd34c>風</color>とでも呼んでください。","ENG":"You can just call me <color=#ffd34c>Wind</color>.","TWN":"就叫我<color=#ffd34c>風</color>吧。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"바람……이요? 이상한 이름이네요…….","JPN":"風……？　変わった名前ですね……","ENG":"Wind...? That's an odd name...","TWN":"風……嗎？好奇怪的名字……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"이곳에서 함부로 이름을 말했다가는 큰일 나거든요.","JPN":"ここでは名前を名乗る事は、とても危険なんです。","ENG":"You'll get in trouble if you carelessly say your name here.","TWN":"在這裡隨便說出本名可是惹禍上身的。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"설마 이름을 부르면 악마가 잡아간다든가…….","JPN":"まさか、名前を名乗ると、悪魔にさらわれてしまうとか……","ENG":"Will a devil come and take you if I say your name...?","TWN":"難道是會被魔鬼抓走嗎……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그거 완전 퇴마 의식에나 나오는 이야기잖아요?","JPN":"完全にエクソシズムの世界の話ですね。","ENG":"That's something straight out of an exorcism!","TWN":"那完全是驅魔儀式裡才會出現的故事吧？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아하하. 침식체에게도 그게 통한다면 언제든 그렇게 했을 텐데 말이에요.\xA0","JPN":"あはは、侵食体にもあんな技が通じるなら、いつでもそうしたいですけどね。\xA0","ENG":"Ah hah hah. If that worked against C.O.s, I would've done it in a heartbeat.","TWN":"呵呵呵，如果驅魔對侵蝕體也有效的話，我早就這麼做了。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"오히려 반대예요. 제 이름을 원하는 건 바로 침식체예요.","JPN":"違います。私の名前を欲しがっているのは、まさに、侵食体なんです。","ENG":"It's the opposite, actually. It's the C.O. that wants my name.","TWN":"恰恰相反，想要我名字的正是侵蝕體。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"이 침식체는 이름에 영혼이 깃들어 있다고 생각하거든요.","JPN":"この侵食体は、名前に魂が宿っていると考えているようです。","ENG":"This C.O. thinks that souls are in names.","TWN":"這個侵蝕體大概是覺得名字裡蘊含著靈魂。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그러니, 어떻게든 제 이름을 감추고 있는 거랍니다.","JPN":"そのため、私は自分の名前を隠すようにしているんです。","ENG":"That's why I'm keeping my real name a secret.","TWN":"所以，我一直在努力隱藏我的名字。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"그리고 그건 당신도 마찬가지예요.","JPN":"そして、それはあなたも同じですよ。","ENG":"It goes for you too.","TWN":"而且你也一樣。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"저만 노리고 있다는 보장이 없으니 조심하시는 게 좋을 걸요?","JPN":"狙われているのが、私だけという保証はないので、気を付けてくださいね。","ENG":"There's no guarantee that it will only target me, so you should also be careful.","TWN":"我不保證它只會盯上我，勸你還是小心為妙。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"히이익!","JPN":"ひいいっ！","ENG":"Heeek!","TWN":"欸！"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"또 한 공간에서만 머물면 위험하죠. 나들이라도 간다 생각하시죠.","JPN":"同じ場所にずっといると危険です。移動ついでに散策でもしてみましょう。","ENG":"Also, it's dangerous to stay in one place. Think of it as going for a walk.","TWN":"一直待在一個地方很危險的，就當是出去散散心吧。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"놈이 우릴 찾아낸다면 좋은 꼴 보기 힘들 테니까요.","JPN":"奴に見つかったら、ただでは済まないので。","ENG":"Because if it finds us, it won't be good for us.","TWN":"如果被那傢伙找到我們，那就麻煩了。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"윽…… 침식파가 가득한 공간에서 나들이라니…… 좀 걱정되는데…….","JPN":"うっ……侵食波が充満している空間を散策だなんて……あまり気が進まないなぁ……","ENG":"Ngh... going for a walk in a space full of Corruption rays... That's a little worrying...","TWN":"呃……在滿是侵蝕波的地方散步……有點擔心呢……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"어쩌면 이곳에서 당신이 원하는 걸 찾을 수도 있잖아요?","JPN":"もしかしたら、あなたが求めているものが、ここで見つかるかもしれませんよ？","ENG":"Maybe you'll find what you're looking for, though.","TWN":"說不定在這裡你能找到你想要的東西呢？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"어쩌면 그럴지도 모르겠네요. 결국 사라진 아버지를 찾으러 이곳에 온 거니까요.","JPN":"そうかもしれませんね。お父さんを探す旅に出ていて、ここに来ることになったのですから。","ENG":"Maybe. I did come here to find my missing father.","TWN":"也許……是這樣沒錯。畢竟我是來這裡尋找失蹤的爸爸的。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"무, 물론 가능성이 낮다는 건 알고 있어요.","JPN":"も、もちろん、可能性が低いことはわかっています。","ENG":"O-of course, I know that my chances are slim.","TWN":"當，當然我知道可能性很低。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"요즘 같은 세상에 사람 하나 사라지는 건 일도 아니니까…….","JPN":"人が一人や二人いなくなることぐらい、よくある世の中ですから……","ENG":"No one bats an eye if someone goes missing these days...","TWN":"在如今這個世界上，消失一個人根本不算什麼……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"아뇨. 분명 찾으실 수 있을 거예요. 제가 응원할게요.","JPN":"いいえ。きっと見つかると思います。応援しますよ。","ENG":"No. I'm sure you'll find him. I'll be rooting for you.","TWN":"不，不用擔心，你一定能找到的。我會支持你的。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"하하…… 감사합니다.","JPN":"はは……ありがとうございます。","ENG":"Haha... Thanks.","TWN":"哈哈……謝謝你。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그나저나…… 에리두가 이렇게 현대적 양식이 많은 도시였을 줄은 몰랐네요.","JPN":"それにしても……エリドゥがこんなに現代的な作りの都市だったとは思いませんでした。","ENG":"Anyway... I didn't know that Eridu was a city that used many modern styles.","TWN":"話說回來……沒想到埃里都竟然擁有如此多的現代風格元素。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"천년의 역사라는 말이 강조되길래 굉장히 올드한 느낌이 들 줄 알았는데.","JPN":"千年の歴史という言葉が強調されているので、もっと古典的な姿を想像していたんです。","ENG":"With a prefix like \\"thousand years of history,\\" I thought it was going to be ancient.","TWN":"聽說有一千年的歷史，我還以為會有很古老的感覺呢。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"이 도시는 고래가 덮어씌운 이면 세계의 일종이에요.","JPN":"この都市は、クジラによって上書きされた一種の裏世界です。","ENG":"This city is a part of the Counterside caused by the whale.","TWN":"這座城市是被鯨魚異界化一部分。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"정말로 당신이 생각하던 에리두라는 도시인지는 모르겠지만…….","JPN":"あなたが言っているエリドゥという都市と、本当に同じ所かどうかはわかりませんが……","ENG":"I don't know if it even is the Eridu that you were imagining, but...","TWN":"我不知道這是不是你所想的那個埃里都城……"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NAME","text":{"KOREA":"지금은 고래가 에리두를 삼키기 전, 어느 한 도시의 기억을 투영하고 있습니다.","JPN":"ここはクジラがエリドゥを飲み込む前の、とある都市の記憶を反映しています。","ENG":"Right now, the whale is projecting memories of a city before it swallowed Eridu.","TWN":"現在，鯨魚投射的是它吞噬埃里都前，某個城市的記憶。"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"다른 도시의…… 기억을 투영한다고요?","JPN":"他の都市の記憶を……反映している？","ENG":"Projecting... another city's memories?","TWN":"投射……某個城市的記憶？"},"stage":{"bg":"CITY_DESERT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};